const messages = items[0].json.messages;

const determinePlanType = (mrr, planType) => {
  const mrrNum = parseFloat(mrr);
  const isMonthly = planType?.toLowerCase().includes('monthly');

  if (mrrNum === 39 && isMonthly) return { plan: 'Business', isLegacy: true };
  if (mrrNum === 29 && !isMonthly) return { plan: 'Business', isLegacy: false };
  if (mrrNum === 19 && isMonthly) return { plan: 'Pro', isLegacy: false };
  if (mrrNum === 15 && !isMonthly) return { plan: 'Pro', isLegacy: true };

  return { plan: 'Unknown', isLegacy: false };
};

const calculateDaysUntilCancellation = (effectiveDate) => {
  if (!effectiveDate || effectiveDate === "N/A") return null;

  try {
    const effective = new Date(effectiveDate);
    const today = new Date();
    const diffTime = effective - today;
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  } catch (error) {
    return null;
  }
};

return messages.map(msg => {
  const data = {
    ts: msg.ts,
    type: msg.text,
    customer: "N/A",
    email: "N/A",
    mrr: "N/A",
    plan_type: "N/A",
    effective_date: "N/A",
    reason: "N/A",
    comment: "N/A",
    plan: "Unknown",
    isLegacy: false,
    days_until_cancellation: null
  };

  const sectionBlock = msg.blocks?.find(b => b.type === 'section' && b.fields);
  if (sectionBlock) {
    sectionBlock.fields.forEach(field => {
      const text = field.text;
      if (text.includes("*Customer:*")) data.customer = text.split('\n')[1];
      if (text.includes("*Email:*")) data.email = text.match(/<mailto:(.*?)\|/)?.[1] || text.split('\n')[1];
      if (text.includes("*MRR:*")) data.mrr = text.split('\n')[1];
      if (text.includes("*Plan Type:*")) data.plan_type = text.split('\n')[1];
      if (text.includes("*Effective Date:*")) data.effective_date = text.split('\n')[1];
      if (text.includes("*Reason:*")) data.reason = text.split('\n')[1];
    });
  }

  const commentBlock = msg.blocks?.find(b => b.type === 'section' && b.text?.text?.includes('Comment'));
  if (commentBlock) {
    const commentMatch = commentBlock.text.text.match(/Comment:\s*(.+)/s);
    if (commentMatch) data.comment = commentMatch[1].trim();
  }

  const planInfo = determinePlanType(data.mrr, data.plan_type);
  data.plan = planInfo.plan;
  data.isLegacy = planInfo.isLegacy;
  data.days_until_cancellation = calculateDaysUntilCancellation(data.effective_date);

  return { json: data };
}).filter(item => item.json.email !== "N/A");

