const aiResponse = $input.first().json;
const originalData = $('Filter: Scheduled Only').item.json;

let parsed;
try {
  parsed = typeof aiResponse.output === 'string' 
    ? JSON.parse(aiResponse.output) 
    : aiResponse.output;
} catch (e) {
  parsed = { subject: 'Follow-up on your YOUR_COMPANY subscription', body: aiResponse.output, tag: 'other' };
}

return [{
  json: {
    ...originalData,
    email_subject: parsed.subject,
    email_body: parsed.body,
    cancellation_tag: parsed.tag
  }
}];

